/**
 * Patient Dashboard Component
 * Dashboard for patient users
 */

import React, { useState, useEffect } from "react";
import {
  Calendar,
  Pill,
  Activity,
  Clock,
  ChevronRight,
  TrendingUp,
  AlertCircle,
  Video,
  MessageSquare,
  User,
} from "lucide-react";
import DashboardHeader from "../components/common/DashboardHeader";
import { medicationsAPI, appointmentsAPI, symptomsAPI } from "../services/api";

const PatientDashboard = ({ user, onLogout }) => {
  const [activeTab, setActiveTab] = useState("overview");
  const [symptomText, setSymptomText] = useState("");
  const [medications, setMedications] = useState([]);
  const [appointments, setAppointments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [symptomAnalysis, setSymptomAnalysis] = useState(null);
  const [analyzing, setAnalyzing] = useState(false);

  // Calculate stats
  const adherenceRate = 87; // This would be calculated from medication tracking data
  const activePrescriptions = medications.length;

  // Find next refill
  const getNextRefillDays = () => {
    const medsNeedingRefill = medications.filter((m) => m.needsRefill);
    if (medsNeedingRefill.length > 0) {
      return Math.min(...medsNeedingRefill.map((m) => m.daysRemaining));
    }
    return medications.length > 0
      ? Math.min(...medications.map((m) => m.daysRemaining))
      : 0;
  };

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);
      const [medsRes, apptsRes] = await Promise.all([
        medicationsAPI.getAll(),
        appointmentsAPI.getAll({ upcoming: "true" }),
      ]);

      if (medsRes.success) setMedications(medsRes.data);
      if (apptsRes.success) setAppointments(apptsRes.data);
    } catch (error) {
      console.error("Error fetching data:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleAnalyzeSymptoms = async () => {
    if (!symptomText.trim()) return;

    try {
      setAnalyzing(true);
      const response = await symptomsAPI.analyze(symptomText);
      if (response.success) {
        setSymptomAnalysis(response.data.analysis);
      }
    } catch (error) {
      console.error("Error analyzing symptoms:", error);
    } finally {
      setAnalyzing(false);
    }
  };

  const nextRefillDays = getNextRefillDays();

  return (
    <div className="min-h-screen bg-gray-50">
      <DashboardHeader user={user} onLogout={onLogout} />

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Welcome Section */}
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-gray-900 mb-2">
            Welcome back, {user?.name?.split(" ")[0] || "Patient"}!
          </h1>
          <p className="text-gray-600">
            Here's your health overview for today.
          </p>
        </div>

        {/* Stats Row */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
          <div className="bg-white rounded-2xl p-6 shadow-md">
            <div className="flex items-center justify-between mb-4">
              <div className="w-12 h-12 bg-teal-100 rounded-xl flex items-center justify-center">
                <TrendingUp className="w-6 h-6 text-teal-600" />
              </div>
              <span className="text-2xl font-bold text-teal-600">
                {adherenceRate}%
              </span>
            </div>
            <h3 className="font-semibold text-gray-900 mb-1">Adherence Rate</h3>
            <p className="text-sm text-gray-500">Great job this week!</p>
          </div>

          <div className="bg-white rounded-2xl p-6 shadow-md">
            <div className="flex items-center justify-between mb-4">
              <div className="w-12 h-12 bg-blue-100 rounded-xl flex items-center justify-center">
                <Calendar className="w-6 h-6 text-blue-600" />
              </div>
              <span className="text-2xl font-bold text-blue-600">
                {nextRefillDays}d
              </span>
            </div>
            <h3 className="font-semibold text-gray-900 mb-1">Next Refill</h3>
            <p className="text-sm text-gray-500">
              {medications.find((m) => m.needsRefill)?.medicineName ||
                "All stocked"}
            </p>
          </div>

          <div className="bg-white rounded-2xl p-6 shadow-md">
            <div className="flex items-center justify-between mb-4">
              <div className="w-12 h-12 bg-purple-100 rounded-xl flex items-center justify-center">
                <Pill className="w-6 h-6 text-purple-600" />
              </div>
              <span className="text-2xl font-bold text-purple-600">
                {activePrescriptions}
              </span>
            </div>
            <h3 className="font-semibold text-gray-900 mb-1">
              Active Prescriptions
            </h3>
            <p className="text-sm text-gray-500">All medications tracked</p>
          </div>
        </div>

        {/* Tabs */}
        <div className="flex space-x-2 mb-6 overflow-x-auto">
          {["overview", "symptoms", "appointments"].map((tab) => (
            <button
              key={tab}
              onClick={() => setActiveTab(tab)}
              className={`px-6 py-3 rounded-xl font-medium transition capitalize whitespace-nowrap ${
                activeTab === tab
                  ? "bg-teal-600 text-white"
                  : "bg-white text-gray-600 hover:bg-gray-50"
              }`}
            >
              {tab}
            </button>
          ))}
        </div>

        {/* Overview Tab */}
        {activeTab === "overview" && (
          <div className="space-y-6">
            <div className="bg-white rounded-2xl p-6 shadow-md">
              <div className="flex items-center justify-between mb-6">
                <h2 className="text-xl font-bold text-gray-900">
                  My Medications
                </h2>
                <button className="text-teal-600 hover:text-teal-700 font-medium text-sm flex items-center">
                  View All <ChevronRight className="w-4 h-4 ml-1" />
                </button>
              </div>

              {loading ? (
                <div className="text-center py-8 text-gray-500">
                  Loading medications...
                </div>
              ) : medications.length === 0 ? (
                <div className="text-center py-8 text-gray-500">
                  <Pill className="w-12 h-12 mx-auto mb-3 text-gray-400" />
                  <p>No medications added yet</p>
                </div>
              ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {medications.slice(0, 4).map((med) => {
                    const stockPercent =
                      (med.remainingStock / med.totalQuantity) * 100;
                    const isLow = med.needsRefill;

                    return (
                      <div
                        key={med._id}
                        className="border border-gray-200 rounded-xl p-4 hover:border-teal-300 transition"
                      >
                        <div className="flex items-start justify-between mb-3">
                          <div>
                            <h3 className="font-semibold text-gray-900">
                              {med.medicineName}
                            </h3>
                            <p className="text-sm text-gray-500">
                              {med.dailyDosage}x daily
                            </p>
                          </div>
                          <div
                            className={`px-3 py-1 rounded-full text-xs font-medium ${
                              isLow
                                ? "bg-rose-100 text-rose-600"
                                : "bg-green-100 text-green-600"
                            }`}
                          >
                            {med.remainingStock} left
                          </div>
                        </div>
                        <div className="space-y-2">
                          <div className="flex items-center justify-between text-sm">
                            <span className="text-gray-600">Stock Level</span>
                            <span className="font-medium">
                              {Math.round(stockPercent)}%
                            </span>
                          </div>
                          <div className="w-full bg-gray-200 rounded-full h-2 overflow-hidden">
                            <div
                              className={`h-full rounded-full transition-all ${
                                isLow ? "bg-rose-500" : "bg-teal-500"
                              }`}
                              style={{
                                width: `${Math.min(stockPercent, 100)}%`,
                              }}
                            ></div>
                          </div>
                          <div className="flex items-center space-x-2 text-xs text-gray-500">
                            <Clock className="w-3 h-3" />
                            <span>{med.daysRemaining} days remaining</span>
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          </div>
        )}

        {/* Symptoms Tab */}
        {activeTab === "symptoms" && (
          <div className="bg-white rounded-2xl p-6 shadow-md">
            <h2 className="text-xl font-bold text-gray-900 mb-4">
              Symptom Checker
            </h2>
            <p className="text-gray-600 mb-6">
              Describe your symptoms and get AI-powered health insights.
            </p>

            <div className="space-y-4">
              <textarea
                value={symptomText}
                onChange={(e) => setSymptomText(e.target.value)}
                placeholder="Example: I've been experiencing headaches and mild fever for the past 2 days..."
                className="w-full h-40 px-4 py-3 border border-gray-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-teal-500 focus:border-transparent resize-none"
              />

              <div className="flex flex-col sm:flex-row gap-3">
                <button
                  onClick={handleAnalyzeSymptoms}
                  disabled={analyzing || !symptomText.trim()}
                  className="flex-1 bg-teal-600 text-white py-3 px-6 rounded-xl hover:bg-teal-700 transition font-semibold flex items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  <Activity className="w-5 h-5 mr-2" />
                  {analyzing ? "Analyzing..." : "Analyze Symptoms"}
                </button>
                <button
                  onClick={() => {
                    setSymptomText("");
                    setSymptomAnalysis(null);
                  }}
                  className="sm:w-auto bg-gray-100 text-gray-700 py-3 px-6 rounded-xl hover:bg-gray-200 transition font-semibold"
                >
                  Clear
                </button>
              </div>

              {symptomAnalysis && (
                <div className="mt-6 p-4 bg-gray-50 rounded-xl space-y-4">
                  <h3 className="font-semibold text-gray-900">
                    Analysis Results
                  </h3>

                  {symptomAnalysis.possibleConditions?.length > 0 && (
                    <div>
                      <p className="text-sm font-medium text-gray-700 mb-2">
                        Possible Conditions:
                      </p>
                      <ul className="space-y-2">
                        {symptomAnalysis.possibleConditions.map(
                          (condition, idx) => (
                            <li
                              key={idx}
                              className="text-sm text-gray-600 flex items-center"
                            >
                              <span className="w-2 h-2 bg-teal-500 rounded-full mr-2"></span>
                              {condition.name} ({condition.probability}%)
                            </li>
                          ),
                        )}
                      </ul>
                    </div>
                  )}

                  {symptomAnalysis.recommendations?.length > 0 && (
                    <div>
                      <p className="text-sm font-medium text-gray-700 mb-2">
                        Recommendations:
                      </p>
                      <ul className="space-y-1">
                        {symptomAnalysis.recommendations.map((rec, idx) => (
                          <li key={idx} className="text-sm text-gray-600">
                            • {rec}
                          </li>
                        ))}
                      </ul>
                    </div>
                  )}

                  <div
                    className={`text-sm px-3 py-2 rounded-lg ${
                      symptomAnalysis.urgencyLevel === "high" ||
                      symptomAnalysis.urgencyLevel === "emergency"
                        ? "bg-rose-100 text-rose-700"
                        : "bg-blue-100 text-blue-700"
                    }`}
                  >
                    Urgency Level:{" "}
                    <span className="font-medium capitalize">
                      {symptomAnalysis.urgencyLevel}
                    </span>
                  </div>
                </div>
              )}

              <div className="bg-blue-50 border border-blue-200 rounded-xl p-4 flex items-start space-x-3">
                <AlertCircle className="w-5 h-5 text-blue-600 flex-shrink-0 mt-0.5" />
                <div className="text-sm text-blue-800">
                  <p className="font-medium mb-1">This is not medical advice</p>
                  <p>
                    Symptom analysis is AI-powered and should not replace
                    professional medical consultation. For emergencies, call
                    911.
                  </p>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Appointments Tab */}
        {activeTab === "appointments" && (
          <div className="bg-white rounded-2xl p-6 shadow-md">
            <h2 className="text-xl font-bold text-gray-900 mb-6">
              Upcoming Appointments
            </h2>

            {loading ? (
              <div className="text-center py-8 text-gray-500">
                Loading appointments...
              </div>
            ) : appointments.length === 0 ? (
              <div className="text-center py-8 text-gray-500">
                <Calendar className="w-12 h-12 mx-auto mb-3 text-gray-400" />
                <p>No upcoming appointments</p>
                <button className="mt-4 text-teal-600 hover:text-teal-700 font-medium">
                  Schedule New Appointment
                </button>
              </div>
            ) : (
              <div className="space-y-4">
                {appointments.map((appointment) => (
                  <div
                    key={appointment._id}
                    className="border border-gray-200 rounded-xl p-4 hover:border-teal-300 transition"
                  >
                    <div className="flex items-center justify-between mb-3">
                      <div className="flex items-center space-x-3">
                        <div
                          className="w-12 h-12 rounded-full flex items-center justify-center"
                          style={{
                            backgroundColor:
                              appointment.doctorId?.avatarColor || "#0D9488",
                          }}
                        >
                          <User className="w-6 h-6 text-white" />
                        </div>
                        <div>
                          <h3 className="font-semibold text-gray-900">
                            Dr. {appointment.doctorId?.name}
                          </h3>
                          <p className="text-sm text-gray-500">
                            {appointment.doctorId?.specialty || "General"}
                          </p>
                        </div>
                      </div>
                      <div className="flex items-center space-x-2">
                        {appointment.type === "video" && (
                          <button className="p-2 bg-blue-100 rounded-lg hover:bg-blue-200 transition">
                            <Video className="w-5 h-5 text-blue-600" />
                          </button>
                        )}
                        <button className="p-2 bg-teal-100 rounded-lg hover:bg-teal-200 transition">
                          <MessageSquare className="w-5 h-5 text-teal-600" />
                        </button>
                      </div>
                    </div>
                    <div className="flex items-center justify-between pt-3 border-t">
                      <div className="flex items-center space-x-2 text-gray-600 text-sm">
                        <Calendar className="w-4 h-4" />
                        <span>
                          {new Date(appointment.scheduledAt).toLocaleDateString(
                            "en-US",
                            {
                              month: "short",
                              day: "numeric",
                              year: "numeric",
                              hour: "2-digit",
                              minute: "2-digit",
                            },
                          )}
                        </span>
                      </div>
                      {appointment.type === "video" && (
                        <button className="bg-teal-600 text-white px-4 py-2 rounded-lg hover:bg-teal-700 transition text-sm font-medium">
                          Join Call
                        </button>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default PatientDashboard;
